 13→/**
 14→ * Factory that dynamically class loads and instantiates an object of type ReturnT
 15→ * @author Stephen Wong
 16→ *
 17→ * @param <ReturnT>  The type of object to be created.
 18→ */
 19→public abstract class AObjectLoader<ReturnT> implements IObjectLoader<ReturnT> {
 20→
 21→	/**
 22→	 * Logger for this and subclasses to use
 23→	 */
 24→	protected ILogger logger = ILoggerControl.getSharedLogger();
 25→
 26→	/**
 27→	 * Maps the primitive  type class to the corresponding wrapper class, e.g.
 28→	 * Integer.TYPE which is the class representation of "int", to
 29→	 * Class&lt;Integer&gt;. This is needed when a primitive input parameter
 30→	 * type is encountered.
 31→	 * An anonymous inner class is used here so that the map can be loaded at instantiation time.
 32→	 */
 33→	private Map<Class<?>, Class<?>> primitiveTypes = new HashMap<Class<?>, Class<?>>() {
 34→		private static final long serialVersionUID = 582688125217694628L;
 35→
 36→		{
 37→			// Manually load the map with the primitive types and their wrapper classes
 38→			Class<?>[][] type2Types = new Class<?>[][] { { Boolean.TYPE, Boolean.class },
 39→					{ Character.TYPE, Character.class }, { Byte.TYPE, Byte.class }, { Short.TYPE, Short.class },
 40→					{ Integer.TYPE, Integer.class }, { Long.TYPE, Long.class }, { Float.TYPE, Float.class },
 41→					{ Double.TYPE, Double.class }, { Void.TYPE, Void.class } };
 42→
 43→			for (Class<?>[] typePair : type2Types) {
 44→				put(typePair[0], typePair[1]);
 45→			}
 46→		}
 47→	};
 48→
 49→	/**
 50→	 * Constructor for the class.   The given errorFac is used to generate instances when the loadInstance() method
 51→	 * is otherwise unable to do so because of a processing error.   Uses the shared logger from ILoggerControl.
 52→	 */
 53→	public AObjectLoader() {
 54→		this(ILoggerControl.getSharedLogger());
 55→	}
 56→
 57→	/**
 58→	 * Constructor for the class.   The given errorFac is used to generate instances when the loadInstance() method
 59→	 * is otherwise unable to do so because of a processing error.
 60→	 * @param logger The logger to use
 61→	 */
 62→	public AObjectLoader(ILogger logger) {
 63→		this.logger = logger;
 64→	}
 65→
 66→	/* (non-Javadoc)
 67→	 * @see util.IObjectLoader#loadInstance(java.lang.String, java.lang.Object)
 68→	 */
 69→	@Override
 70→	@SuppressWarnings("unchecked")
 71→	public ReturnT loadInstance(String className, Object... args) {
 72→		try {
 73→			Objects.requireNonNull(className, "Given classname was null!");
 74→			Class<?> objectClass = Class.forName(className);
 75→			return (ReturnT) getConstructor(objectClass, args).newInstance(args);
 76→
 77→		} catch (Exception ex) {
 78→			return errorHandler(ex, className, args); // delegate to the abstract error handler
 79→		} catch (NoClassDefFoundError err) { // NoClassDefFound Error is not an Exception so must be handled separately.
 80→			String errorMsg = "[AObjectLoader.loadInstance()] Invalid class name: " + className;
 81→			logger.log(LogLevel.ERROR, errorMsg);
 82→			return errorHandler(new TypeNotPresentException(errorMsg, err), className, args); // delegate to the abstract error handler, converting the Error to the equivalent Exception
 83→		}
 84→	}
 85→
 86→	/**
 87→	 * Abstract loading exception handler method
 88→	 * @param ex The Exception that was generated
 89→	 * @param className The fully qualified name of the class that was attempted to be loaded
 90→	 * @param args The constructor parameters for the given class name.
 91→	 * @return An "error" object
 92→	 */
 93→	abstract protected ReturnT errorHandler(Exception ex, String className, Object... args);
 94→
 95→	/**
 96→	 * Proper form of Class.getConstructor(Class&lt;?&gt;[] parameterTypes) that
 97→	 * returns a constructor that will return a constructor of the given class
 98→	 * that will accept the given argument list.  Correctly finds a constructor
 99→	 * even if the constructor types are superclasses of the given arguments except 
100→	 * that it will not necessarily choose the more narrowed choice if more than one 
101→	 * possibility exists. 
102→	 * 
103→	 * @param aClass
104→	 *            A class object whose constructor is being searched for.
105→	 * @param args
106→	 *            a list of input values for the constructor
107→	 * @return a Constructor&lt;?&gt; that will work with the given set of input
108→	 *         parameter values.
109→	 * @throws IllegalArgumentException
110→	 *             when no constructor can be found that would accept the given
111→	 *             parameters.
112→	 */
113→	private Constructor<?> getConstructor(Class<?> aClass, Object[] args) throws IllegalArgumentException {
114→		// Get all the constructors of the given class
115→		Constructor<?> cs[] = aClass.getConstructors();
116→
117→		// search the constructors for the first one whose types allow the given input values.
118→		for (int i = 0; i < cs.length; i++) {
119→			if (checkTypes(cs[i].getParameterTypes(), args)) {
120→				return cs[i]; // Found one! Return the constructor.   note that there might be more that would fit, perhaps better than this one.
121→			}
122→		}
123→		throw new IllegalArgumentException(
124→				"No constructor found that matches the arguments of the given input parameters.");
125→	}
126→
127→	/**
128→	 * Utility method to check if the types of the elements in the given args
129→	 * array match the types in the given paramTypes array. That is, if a method
130→	 * takes input parameters of types paramTypes, would args be an allowable
131→	 * input?
132→	 * 
133→	 * @param paramTypes
134→	 *            An array of Class objects representing an ordered list of
135→	 *            types
136→	 * @param args
137→	 *            An array of input parameter values, whose types are being
138→	 *            checked against paramTypes.
139→	 * @return true if all arg elements are subclasses (assignable to) their
140→	 *         corresponding paramTypes elements. Returns false otherwise.
141→	 */
142→	private boolean checkTypes(Class<?>[] paramTypes, Object[] args) {
143→		if (args.length == paramTypes.length) {
144→			for (int idx = 0; idx < args.length; idx++) {
145→				// Special case if the input parameter is a primitive.
146→				// e.g.  Integer.TYPE is the type of int and even though int x = new Integer(42) is ok,
147→				// Integer.TYPE.isAssignableFrom(Integer.class) will return false!!!
148→				if (paramTypes[idx].isPrimitive()) {
149→					// Substitute the boxing class of the primitive type, e.g. Integer for int
150→					paramTypes[idx] = primitiveTypes.get(paramTypes[idx]);
151→				}
152→				// check if input parameter is an allowable subclass of the formal constructor parameter type.
153→				if (!paramTypes[idx].isAssignableFrom(args[idx].getClass())) {
154→					return false; // Types don't match
155→				}
156→			}
157→			return true; // types match!
158→		} else {
159→			return false; // wrong number of input parameters
160→		}
161→	}
162→}
